            updated_at: Some(1_700_000_000),
        };
        let json = serde_json::to_string(&loc).unwrap();
        let parsed: GeoLocation = serde_json::from_str(&json).unwrap();
        assert_eq!(parsed.place.as_deref(), Some("Paris, France"));
    }

