            }),
        );

        let chat = LiveChatService::new(
            Arc::new(RwLock::new(providers)),
            Arc::new(RwLock::new(DisabledModelsStore::default())),
            Arc::new(MockChatRuntime::new().with_active_session("conn-1", "conn-session")),
